query GetDeviceAnalytics($first: Int, $where: CampaignOrderWhereInput) {
  campaignOrdersConnection(first: $first, where: $where) {
    edges {
      node {
        id
        name
        status
        aggregateData {
          id
          deviceClicks
        }
      }
    }
    aggregate {
      count
    }
  }
}

query GetMultipleCampaignDeviceData($first: Int, $where: CampaignOrderWhereInput, $orderBy: CampaignOrderOrderByInput) {
  campaignOrdersConnection(first: $first, where: $where, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        status
        aggregateData {
          id
          deviceClicks
        }
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}

query GetDeviceDataByDateRange($first: Int, $where: CampaignOrderWhereInput, $orderBy: CampaignOrderOrderByInput) {
  campaignOrdersConnection(first: $first, where: $where, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        status
        startDate
        endDate
        aggregateData {
          id
          deviceClicks
        }
      }
    }
    aggregate {
      count
    }
  }
}

query GetSessionsByDevice($first: Int) {
  campaignOrderSessionsWithEventsesConnection(first: $first) {
    edges {
      node {
        id
        sessionId
        deviceType
        pageViews
        durationInSeconds
        totalImpressions
        landingPage
        attrMethod
        start
        end
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
